<?phpinclude 'heador.php';include 'dbconnect.php';//open up databasemysql_select_db('HELPDISK');$cat = $_GET['cat'];$result = mysql_query ("SELECT * FROM url WHERE category ='$cat'");while($row = mysql_fetch_array($result, MYSQL_BOTH)){	print ("<a href=\"".$row["url"]."\" target=\"_blank\"> ".$row["name"]."</a><br>\n");}//close user connectionmysql_free_result($result);?></DIV></BODY></HTML>